14	// TestRecoverGitIndexLock_NoLock returns "not present" cleanly when the
15	// lock file does not exist.
16	func TestRecoverGitIndexLock_NoLock(t *testing.T) {
17		dir := t.TempDir()
18		if err := os.Mkdir(filepath.Join(dir, ".git"), 0o755); err != nil {
19			t.Fatalf("setup .git: %v", err)
20		}
21		result, err := recoverGitIndexLock(dir)
22		if err != nil {
23			t.Fatalf("recoverGitIndexLock: %v", err)
24		}
25		if result.Removed {
26			t.Fatalf("Removed=true for missing lock")
27		}
28		if !strings.Contains(result.Reason, "not present") {
29			t.Fatalf("Reason: %q", result.Reason)
30		}
31	}
