33	// TestRecoverGitIndexLock_StaleByAge removes an unowned lock once it is
34	// older than gitlock.StaleAge.
35	func TestRecoverGitIndexLock_StaleByAge(t *testing.T) {
36		prev := gitlock.StaleAge
37		gitlock.StaleAge = 50 * time.Millisecond
38		t.Cleanup(func() { gitlock.StaleAge = prev })
39	
40		dir := t.TempDir()
41		if err := os.Mkdir(filepath.Join(dir, ".git"), 0o755); err != nil {
42			t.Fatalf("setup .git: %v", err)
43		}
44		lockPath := filepath.Join(dir, ".git", "index.lock")
45		if err := os.WriteFile(lockPath, nil, 0o644); err != nil {
46			t.Fatalf("create lock: %v", err)
47		}
48		old := time.Now().Add(-1 * time.Second)
49		if err := os.Chtimes(lockPath, old, old); err != nil {
50			t.Fatalf("chtimes: %v", err)
51		}
52	
53		result, err := recoverGitIndexLock(dir)
54		if err != nil {
55			t.Fatalf("recoverGitIndexLock: %v", err)
56		}
57		if !result.Removed {
58			t.Fatalf("expected Removed=true, got reason=%q", result.Reason)
59		}
60		if _, err := os.Stat(lockPath); !os.IsNotExist(err) {
61			t.Fatalf("lock still exists after recovery: %v", err)
62		}
63	}
