65	// TestRecoverGitIndexLock_FreshUnowned leaves a fresh unowned lock in
66	// place — the lock might belong to a transient operator command that has
67	// not yet been picked up by lsof, so we wait rather than break it.
68	func TestRecoverGitIndexLock_FreshUnowned(t *testing.T) {
69		prev := gitlock.StaleAge
70		gitlock.StaleAge = 1 * time.Hour
71		t.Cleanup(func() { gitlock.StaleAge = prev })
72	
73		dir := t.TempDir()
74		if err := os.Mkdir(filepath.Join(dir, ".git"), 0o755); err != nil {
75			t.Fatalf("setup .git: %v", err)
76		}
77		lockPath := filepath.Join(dir, ".git", "index.lock")
78		if err := os.WriteFile(lockPath, nil, 0o644); err != nil {
79			t.Fatalf("create lock: %v", err)
80		}
81	
82		result, err := recoverGitIndexLock(dir)
83		if err != nil {
84			t.Fatalf("recoverGitIndexLock: %v", err)
85		}
86		if result.Removed {
87			t.Fatalf("fresh unowned lock should not be removed")
88		}
89		if _, err := os.Stat(lockPath); err != nil {
90			t.Fatalf("lock should still exist: %v", err)
91		}
92	}
