94	// TestRecoverGitIndexLock_DeadOwner removes the lock when lsof identifies
95	// a pid that is not alive. This test requires lsof and is skipped if
96	// unavailable.
97	func TestRecoverGitIndexLock_DeadOwner(t *testing.T) {
98		if _, err := exec.LookPath("lsof"); err != nil {
99			t.Skip("lsof not available on PATH")
100		}
101	
102		dir := t.TempDir()
103		if err := os.Mkdir(filepath.Join(dir, ".git"), 0o755); err != nil {
104			t.Fatalf("setup .git: %v", err)
105		}
106		lockPath := filepath.Join(dir, ".git", "index.lock")
107	
108		// Spawn a short-lived process that opens the lock file, then exits.
109		cmd := exec.Command("sh", "-c", "exec 9>>"+lockPath+"; sleep 0.05")
110		if err := cmd.Start(); err != nil {
111			t.Fatalf("start helper: %v", err)
112		}
113		if err := cmd.Wait(); err != nil {
114			t.Fatalf("helper exited with error: %v", err)
115		}
116		// Helper is dead; age the lock past stale threshold so the unowned-stale branch removes it.
117		prev := gitlock.StaleAge
118		gitlock.StaleAge = 1 * time.Millisecond
119		t.Cleanup(func() { gitlock.StaleAge = prev })
120	
121		time.Sleep(5 * time.Millisecond)
122		result, err := recoverGitIndexLock(dir)
123		if err != nil {
124			t.Fatalf("recoverGitIndexLock: %v", err)
125		}
126		if !result.Removed {
127			t.Fatalf("expected removal, reason=%q owner=%d alive=%v",
128				result.Reason, result.OwnerPID, result.OwnerAlive)
129		}
130	}
