132	func TestIsGitIndexLockError(t *testing.T) {
133		cases := []struct {
134			name string
135			s    string
136			want bool
137		}{
138			{"fatal_file_exists", "fatal: Unable to create '/repo/.git/index.lock': File exists.", true},
139			{"combined_git_message", "fatal: Unable to create '/repo/.git/index.lock': File exists.\n\nAnother git process seems to be running in this repository", true},
140			{"unrelated", "fatal: not a git repository", false},
141			{"empty", "", false},
142		}
143		for _, tc := range cases {
144			t.Run(tc.name, func(t *testing.T) {
145				if got := gitlock.IsIndexLockError(tc.s); got != tc.want {
146					t.Fatalf("gitlock.IsIndexLockError(%q) = %v, want %v", tc.s, got, tc.want)
147				}
148			})
149		}
150	}
