46	// CommitDurableAuditOutputs stages and commits the DDx-managed durable audit
47	// paths when they are dirty. The commit is serialized through the main git lock
48	// so concurrent workers cannot interleave tracker and audit commits.
49	func CommitDurableAuditOutputs(projectRoot, attemptID string) error {
50		return withTrackerLock(projectRoot, func() error {
51			return commitDurableAuditOutputsLocked(projectRoot, attemptID)
