445	func publishCloneResult(ctx context.Context, ws *AttemptWorkspace, res *ExecuteBeadResult) error {
446		if ws == nil || res == nil || ws.WorkDir == "" || ws.ProjectRoot == "" {
447			return nil
448		}
449		resultRev := strings.TrimSpace(res.ResultRev)
450		if resultRev == "" || resultRev == res.BaseRev {
451			return nil
452		}
453		srcRef := attemptBackendResultRef("source", ws.BeadID, ws.AttemptID)
454		dstRef := attemptBackendResultRef("result", ws.BeadID, ws.AttemptID)
455		if out, err := internalgit.Command(ctx, ws.WorkDir, "update-ref", srcRef, resultRev).CombinedOutput(); err != nil {
456			return fmt.Errorf("pinning clone result ref: %s: %w", strings.TrimSpace(string(out)), err)
457		}
458		refspec := "+" + srcRef + ":" + dstRef
459		if out, err := internalgit.Command(ctx, ws.ProjectRoot, "fetch", "--no-tags", ws.WorkDir, refspec).CombinedOutput(); err != nil {
460			return fmt.Errorf("importing clone result: %s: %w", strings.TrimSpace(string(out)), err)
461		}
462		return nil
463	}
