476	func resolveDockerAttemptImage(ctx context.Context, cfg *config.ExecutionsDockerConfig, projectRoot, baseImage string) (string, error) {
477		if cfg != nil && strings.TrimSpace(cfg.ProjectImage) != "" {
478			return strings.TrimSpace(cfg.ProjectImage), nil
479		}
480		dockerfile, ok, err := dockerProjectDockerfile(projectRoot, cfg)
481		if err != nil || !ok {
482			return baseImage, err
483		}
484		contextDir, err := dockerProjectContext(projectRoot, cfg)
485		if err != nil {
486			return "", err
487		}
488		tag := "ddx-project-attempt-" + shortPathHash(projectRoot) + ":latest"
489		if skipRebuildIfImagePresent(cfg) && dockerImageExists(ctx, tag) {
490			return tag, nil
491		}
492		args := []string{
493			"build", "-q",
494			"--build-arg", "DDX_BASE_IMAGE=" + baseImage,
495			"-f", dockerfile,
496			"-t", tag,
497			contextDir,
498		}
499		if out, err := exec.CommandContext(ctx, "docker", args...).CombinedOutput(); err != nil {
500			return "", fmt.Errorf("building docker project attempt image: %s: %w", strings.TrimSpace(string(out)), err)
501		}
502		return tag, nil
503	}
