566	func dockerProjectContext(projectRoot string, cfg *config.ExecutionsDockerConfig) (string, error) {
567		configured := ""
568		if cfg != nil {
569			configured = strings.TrimSpace(cfg.ProjectContext)
570		}
571		if configured == "" {
572			return projectRoot, nil
573		}
574		path, err := projectBoundPath(projectRoot, configured)
575		if err != nil {
576			return "", fmt.Errorf("docker project context: %w", err)
577		}
578		info, err := os.Stat(path)
579		if err != nil {
580			return "", fmt.Errorf("docker project context %s: %w", path, err)
581		}
582		if !info.IsDir() {
583			return "", fmt.Errorf("docker project context is not a directory: %s", path)
584		}
585		return path, nil
586	}
587	
588	func projectBoundPath(projectRoot, path string) (string, error) {
589		if strings.TrimSpace(path) == "" {
590			return "", fmt.Errorf("path is empty")
591		}
592		if !filepath.IsAbs(path) {
593			path = filepath.Join(projectRoot, filepath.FromSlash(path))
594		}
595		cleanRoot := filepath.Clean(projectRoot)
596		cleanPath := filepath.Clean(path)
597		rel, err := filepath.Rel(cleanRoot, cleanPath)
598		if err != nil {
599			return "", err
600		}
601		if rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
602			return "", fmt.Errorf("path escapes project root: %s", path)
603		}
604		return cleanPath, nil
605	}
