612	func dockerRunArgs(cfg *config.ExecutionsDockerConfig, ws *AttemptWorkspace, exe, image string, tools []dockerToolMount) []string {
613		name := dockerContainerName(ws)
614		args := []string{
615			"run", "--rm", "--init",
616			"--name", name,
617			"--label", "ddx.backend=docker-clone",
618			"--label", "ddx.attempt=" + ws.AttemptID,
619			"--label", "ddx.project=" + shortPathHash(ws.ProjectRoot),
620			"--user", fmt.Sprintf("%d:%d", os.Getuid(), os.Getgid()),
621			"--workdir", "/work",
622			"--mount", "type=bind,src=" + ws.WorkDir + ",dst=/work",
623			"--mount", "type=bind,src=" + exe + ",dst=/usr/local/bin/ddx,readonly",
624			"-e", "PATH=/usr/local/go/bin:/opt/go/bin:/usr/local/bin:/usr/bin:/bin",
625			"-e", "HOME=/ddx-runtime/home",
626			"-e", "XDG_CACHE_HOME=/ddx-runtime/cache",
627			"-e", "TMPDIR=/ddx-runtime/tmp",
628			"-e", "GOCACHE=/work/.gocache",
629			"-e", "GOTMPDIR=/ddx-runtime/go-tmp",
630			"-e", "DDX_PROJECT_ROOT=/work",
631			"-e", DDXModeEnvKey + "=" + DDXModeBeadExecution,
632			"-e", "DDX_BEAD_ID=" + ws.BeadID,
633			"-e", "DDX_ATTEMPT_ID=" + ws.AttemptID,
634		}
635		if ws.DockerRun != "" {
636			args = append(args, "--mount", "type=bind,src="+ws.DockerRun+",dst=/ddx-runtime")
637			gocacheSrc := filepath.Join(ws.DockerRun, "work-gocache")
638			if ws.DockerSharedGoCache != "" {
639				gocacheSrc = ws.DockerSharedGoCache
640			}
641			args = append(args, "--mount", "type=bind,src="+gocacheSrc+",dst=/work/.gocache")
642			args = append(args, "--mount", "type=bind,src="+filepath.Join(ws.DockerRun, "work-tmp")+",dst=/work/.tmp")
643		}
644		for _, tool := range tools {
645			if tool.Name == "" || tool.Path == "" {
646				continue
647			}
648			args = append(args, "--mount", "type=bind,src="+tool.Path+",dst=/usr/local/bin/"+tool.Name+",readonly")
649		}
650		for _, env := range dockerCredentialEnv() {
651			args = append(args, "-e", env)
652		}
653		tmpfsSize := "2g"
654		if cfg != nil && strings.TrimSpace(cfg.TmpfsSize) != "" {
655			tmpfsSize = strings.TrimSpace(cfg.TmpfsSize)
656		}
657		args = append(args, "--tmpfs", "/tmp:rw,nosuid,nodev,size="+tmpfsSize+",mode=1777")
658		if cfg != nil {
659			if cfg.Memory != "" {
660				args = append(args, "--memory", cfg.Memory)
661			}
662			if cfg.MemorySwap != "" {
663				args = append(args, "--memory-swap", cfg.MemorySwap)
664			}
665			if cfg.CPUs != "" {
666				args = append(args, "--cpus", cfg.CPUs)
667			}
668			if cfg.PidsLimit > 0 {
669				args = append(args, "--pids-limit", strconv.Itoa(cfg.PidsLimit))
670			}
671			if cfg.Network != "" {
672				args = append(args, "--network", cfg.Network)
673			}
674		}
675		return append(args, image)
676	}
