739	func prepareDockerAttemptHome(homeDir string) error {
740		if strings.TrimSpace(homeDir) == "" {
741			return nil
742		}
743		if err := os.RemoveAll(homeDir); err != nil {
744			return fmt.Errorf("resetting docker attempt home: %w", err)
745		}
746		if err := os.MkdirAll(homeDir, 0o700); err != nil {
747			return fmt.Errorf("creating docker attempt home: %w", err)
748		}
749		hostHome, err := os.UserHomeDir()
750		if err != nil {
751			return nil
752		}
753		for _, file := range []struct {
754			src string
755			dst string
756		}{
