776	func copyDockerAuthFileIfExists(src, dst string) error {
777		info, err := os.Stat(src)
778		if err != nil {
779			if os.IsNotExist(err) {
780				return nil
781			}
782			return fmt.Errorf("stat docker auth file %s: %w", src, err)
783		}
784		if info.IsDir() {
785			return nil
786		}
787		raw, err := os.ReadFile(src)
