800	func dockerCredentialEnv() []string {
801		prefixes := []string{
802			"ANTHROPIC_", "CODEX_", "FIZEAU_", "GEMINI_", "GOOGLE_",
803			"OPENAI_", "OPENROUTER_",
804		}
805		var env []string
806		for _, kv := range os.Environ() {
807			name, _, ok := strings.Cut(kv, "=")
808			if !ok {
809				continue
810			}
811			for _, prefix := range prefixes {
812				if strings.HasPrefix(name, prefix) {
