821	func containerPath(root, path string) (string, error) {
822		if strings.TrimSpace(path) == "" {
823			return "", fmt.Errorf("docker-clone attempt requires a prompt file inside the workspace")
824		}
825		rel, err := filepath.Rel(root, path)
826		if err != nil || rel == "." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) || rel == ".." {
827			return "", fmt.Errorf("docker-clone prompt file must be inside the attempt workspace: %s", path)
828		}
