832	func parseDockerRunResult(raw []byte) (*Result, error) {
833		trimmed := bytes.TrimSpace(raw)
834		if len(trimmed) == 0 {
835			return nil, fmt.Errorf("docker-clone produced no JSON result")
836		}
837		start := bytes.IndexByte(trimmed, '{')
838		if start < 0 {
839			return nil, fmt.Errorf("docker-clone output did not contain a JSON result")
840		}
841		var result Result
842		if err := json.Unmarshal(trimmed[start:], &result); err != nil {
843			return nil, fmt.Errorf("decoding docker-clone JSON result: %w", err)
844		}
845		return &result, nil
846	}
