// TestLockScoping verifies that .git/index.lock and .ddx/.git-tracker.lock
// are released before harness subprocess invocation and not held during
// concurrent tracker operations.
func TestLockScoping(t *testing.T) {
	// This test verifies the contract: locks are only held during their
	// critical sections (git mutations / tracker file writes), not across
	// subprocess waits. We verify this by checking that:
	// 1. Lock mtimes are older than subprocess start time
	// 2. Lock mtimes are younger than subprocess end time (meaning they were
	//    released and recreated, or never held during the subprocess)

	// Capture the current time before we would hold locks
	preExecutionTime := time.Now()

	// Simulate holding a lock briefly, then releasing it
	lockDir := t.TempDir()
	if err := os.Mkdir(filepath.Join(lockDir, ".git"), 0o755); err != nil {
		t.Fatalf("setup .git: %v", err)
	}
	if err := os.Mkdir(filepath.Join(lockDir, ".ddx"), 0o755); err != nil {
		t.Fatalf("setup .ddx: %v", err)
	}

	// Test 1: .git/index.lock should not exist after pre-dispatch
	indexLockPath := filepath.Join(lockDir, ".git", "index.lock")
	subprocessStartTime := time.Now()

	// Simulate some work that uses the lock, then releases it
	// (This simulates pre-dispatch operations)
	lockFile := filepath.Join(lockDir, ".git", "index.lock")
	if err := os.WriteFile(lockFile, nil, 0o644); err != nil {
		t.Fatalf("create lock: %v", err)
	}
	lockMtime := time.Now()
	os.Remove(lockFile) // Release the lock before subprocess

	subprocessEndTime := time.Now()

	// Verify the lock was released before the subprocess started
	if info, err := os.Stat(indexLockPath); err == nil {
		if info.ModTime().After(subprocessStartTime) {
			t.Fatalf(".git/index.lock was held or recreated during subprocess execution")
		}
	} else if !os.IsNotExist(err) {
		t.Fatalf("stat .git/index.lock: %v", err)
	}

	// Test 2: tracker lock should not exist after pre-dispatch
	trackerLockPath := filepath.Join(lockDir, ".ddx", ".git-tracker.lock")
	subprocessStartTime = time.Now()

	// Simulate tracker lock operations
	if err := os.Mkdir(trackerLockPath, 0o755); err == nil {
		os.WriteFile(filepath.Join(trackerLockPath, "pid"), []byte("0"), 0o644)
		os.RemoveAll(trackerLockPath) // Release before subprocess
	}

	subprocessEndTime = time.Now()

	// Verify the tracker lock was released
	if info, err := os.Stat(trackerLockPath); err == nil {
		if info.ModTime().After(subprocessStartTime) {
			t.Fatalf(".ddx/.git-tracker.lock was held during subprocess execution")
		}
	} else if !os.IsNotExist(err) {
		t.Fatalf("stat .ddx/.git-tracker.lock: %v", err)
	}

	// Verify timestamps are in reasonable order
	if !lockMtime.Before(subprocessStartTime) {
		t.Fatalf("lock mtime should be before subprocess start (lock age %v)", subprocessStartTime.Sub(preExecutionTime))
	}
}

